{
    "title": "6. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose the correct Past Simple question or short answer.",
    "selects": [
        {
            "label": "a) Did you see him yesterday? / b) Did you saw him yesterday?",
            "prompt": "Which option is correct?",
            "answer": "a"
        },
        {
            "label": "a) Did she went home? / b) Did she go home?",
            "prompt": "Which option is correct?",
            "answer": "b"
        },
        {
            "label": "a) Yes, I did. / b) Yes, I do.",
            "prompt": "Which option is correct?",
            "answer": "a"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Exercise 2. Build the question",
    "input_intro": "Put did at the beginning and keep the main verb in V1.",
    "inputs": [
        {
            "before": "the film / watch / you?",
            "after": "→",
            "answer": "Did you watch the film?"
        },
        {
            "before": "yesterday / you / she / call?",
            "after": "→",
            "answer": "Did she call you yesterday?"
        },
        {
            "before": "on time / arrive / they?",
            "after": "→",
            "answer": "Did they arrive on time?"
        }
    ],
    "rephrase_title": "Exercise 3. Correct the mistakes",
    "rephrase_intro": "Find the mistake in the question or short answer.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "Did he went home?",
            "example_target": "Did he go home?"
        },
        {
            "original": "1. Did he went home?",
            "placeholder": "Correct the sentence",
            "answer": "Did he go home?"
        },
        {
            "original": "2. You saw her yesterday?",
            "placeholder": "Correct the sentence",
            "answer": "Did you see her yesterday?"
        },
        {
            "original": "3. Yes, she do.",
            "placeholder": "Correct the answer",
            "answer": "Yes, she did."
        }
    ]
}
